import Navbar from "./Navbar";
import Title from './Title'
import theme from '../theme'

const Layout = ({ children }) => {

  return (
    <>
      <style>{style}</style>
      <div className='wrapper'>
        <Title />
        <Navbar />
        {children}
      </div>
    </>
  )
};

const style = `
  * {
    font-family:Roboto;
  }
  ol {
      padding-left:1rem;
  }
  .overall-wrapper {
    position: fixed;
    top:0;
    width: 100vw;
    height: 100vh;
  }
  .wrapper {
    width:70vw;
    margin:auto;
    min-width:600px;
    background-color:rgba(255,0,0,10);
  }
  body {
    background-color:${theme.darkBackground};
  }
  iframe {
    width:100vw;
    height:100vh;
    border:none;
  }
`;

export default Layout;
